     1|/**
     2| * IVX rate-limit middleware (token-bucket, in-memory, per IP+user).
     3| *
     4| * Protects expensive senior-dev endpoints (/proof, /repo-search,
     5| * /execution-stream, /test-report, /e2e/run) from abuse and runaway
     6| * cost. Returns 429 with a `Retry-After` (seconds) header when burst
     7| * exceeded. Buckets self-prune to bound memory.
     8| *
     9| * Zero external deps; safe to use on Hono, Bun, Node, Cloudflare
    10| * Workers (per-isolate). For multi-instance correctness, a shared
    11| * store (Redis/Durable Object) can replace `BUCKETS` later — this
    12| * version is correct per-instance and never crashes.
    13| */
    14|export type RateLimitOptions = {
    15|  /** Max burst tokens (e.g. 30 → 30 requests instantly). */
    16|  burst: number;
    17|  /** Token refill rate per second (e.g. 1 → +1 token / sec). */
    18|  refillPerSecond: number;
    19|  /** Optional bucket-key suffix to namespace different endpoints. */
    20|  scope: string;
    21|};
    22|
    23|type Bucket = {
    24|  tokens: number;
    25|  lastRefillMs: number;
    26|  lastSeenMs: number;
    27|};
    28|
    29|const BUCKETS = new Map<string, Bucket>();
    30|const MAX_BUCKETS = 5000;
    31|const PRUNE_AFTER_MS = 10 * 60 * 1000;
    32|
    33|function getClientKey(request: Request, scope: string): string {
    34|  const headers = request.headers;
    35|  const ip =
    36|    headers.get('cf-connecting-ip') ??
    37|    headers.get('x-real-ip') ??
    38|    (headers.get('x-forwarded-for') ?? '').split(',')[0].trim() ??
    39|    'unknown';
    40|  const auth = headers.get('authorization') ?? '';
    41|  // Hash the token suffix only (never log it) so different owner sessions
    42|  // get separate buckets without leaking the token.
    43|  const authSuffix = auth.length > 8 ? auth.slice(-8) : auth;
    44|  return `${scope}|${ip}|${authSuffix}`;
    45|}
    46|
    47|function pruneIfNeeded(now: number): void {
    48|  if (BUCKETS.size < MAX_BUCKETS) return;
    49|  for (const [k, b] of BUCKETS) {
    50|    if (now - b.lastSeenMs > PRUNE_AFTER_MS) BUCKETS.delete(k);
    51|    if (BUCKETS.size < MAX_BUCKETS * 0.8) break;
    52|  }
    53|}
    54|
    55|/**
    56| * Attempt to consume 1 token. Returns null if allowed, or a 429
    57| * Response if rate-limited (with Retry-After).
    58| */
    59|export function checkRateLimit(request: Request, opts: RateLimitOptions): Response | null {
    60|  const now = Date.now();
    61|  const key = getClientKey(request, opts.scope);
    62|  const bucket = BUCKETS.get(key) ?? { tokens: opts.burst, lastRefillMs: now, lastSeenMs: now };
    63|  // Refill
    64|  const elapsedSec = Math.max(0, (now - bucket.lastRefillMs) / 1000);
    65|  bucket.tokens = Math.min(opts.burst, bucket.tokens + elapsedSec * opts.refillPerSecond);
    66|  bucket.lastRefillMs = now;
    67|  bucket.lastSeenMs = now;
    68|
    69|  if (bucket.tokens < 1) {
    70|    const needed = 1 - bucket.tokens;
    71|    const retryAfterSec = Math.max(1, Math.ceil(needed / Math.max(0.0001, opts.refillPerSecond)));
    72|    BUCKETS.set(key, bucket);
    73|    pruneIfNeeded(now);
    74|    return new Response(
    75|      JSON.stringify({ ok: false, error: 'rate_limited', retryAfterSec, scope: opts.scope }),
    76|      {
    77|        status: 429,
    78|        headers: {
    79|          'content-type': 'application/json',
    80|          'retry-after': String(retryAfterSec),
    81|          'x-ratelimit-scope': opts.scope,
    82|          'x-ratelimit-burst': String(opts.burst),
    83|          'x-ratelimit-refill-per-second': String(opts.refillPerSecond),
    84|        },
    85|      },
    86|    );
    87|  }
    88|
    89|  bucket.tokens -= 1;
    90|  BUCKETS.set(key, bucket);
    91|  pruneIfNeeded(now);
    92|  return null;
    93|}
    94|
    95|/** Test/debug helper — never used in production paths. */
    96|export function _resetIVXRateLimitForTests(): void {
    97|  BUCKETS.clear();
    98|}
