    22|export const IVX_METRICS_AGGREGATOR_MARKER = 'ivx-metrics-aggregator-2026-06-01';
    23|
    24|const DAY_MS = 24 * 60 * 60 * 1000;
    25|
    26|/** Latency distribution for a metric over a single window. */
    27|export type LatencyStats = {
    28|  count: number;
    29|  avgMs: number | null;
    30|  p50Ms: number | null;
    31|  p95Ms: number | null;
    32|  maxMs: number | null;
    33|  minMs: number | null;
    34|};
    35|
    36|/** Success-rate roll-up for a metric over a single window. */
    37|export type SuccessStats = {
