    70|function percentile(sortedAsc: number[], p: number): number | null {
    71|  if (sortedAsc.length === 0) return null;
    72|  if (sortedAsc.length === 1) return sortedAsc[0];
    73|  const rank = (p / 100) * (sortedAsc.length - 1);
    74|  const low = Math.floor(rank);
    75|  const high = Math.ceil(rank);
    76|  if (low === high) return sortedAsc[low];
    77|  const weight = rank - low;
    78|  return Math.round(sortedAsc[low] * (1 - weight) + sortedAsc[high] * weight);
