    81|function computeLatency(samples: MetricSample[]): LatencyStats {
    82|  const values = samples
    83|    .map((s) => s.latencyMs)
    84|    .filter((v): v is number => typeof v === 'number' && Number.isFinite(v) && v >= 0)
