    90|  return {
    91|    count: values.length,
    92|    avgMs: Math.round(sum / values.length),
    93|    p50Ms: percentile(values, 50),
    94|    p95Ms: percentile(values, 95),
    95|    maxMs: values[values.length - 1],
    96|    minMs: values[0],
    97|  };
