   100|function computeSuccess(samples: MetricSample[]): SuccessStats {
   101|  const total = samples.length;
   102|  const success = samples.filter((s) => s.success).length;
   103|  const failure = total - success;
   104|  return {
   105|    total,
   106|    success,
   107|    failure,
   108|    successRate: total > 0 ? Math.round((success / total) * 1000) / 10 : null,
   109|  };
